import React, { useState } from 'react';
import { Avatar, Stars, StatusBadge } from '../components/UI';

export default function ProviderPage({ providers, bookings, onPost, onAccept }) {
  const [tab, setTab] = useState('available');

  const myProfile    = providers.find(p => p.id === 'myprofile');
  const available    = bookings.filter(b => b.status === 'Pending');
  const myAccepted   = bookings.filter(b => b.status === 'Accepted' && b.providerId === 'myprofile');
  const myCompleted  = bookings.filter(b => b.status === 'Completed' && b.providerId === 'myprofile');

  const STATS = [
    ['Available Jobs', available.length,   '📋'],
    ['My Active Jobs', myAccepted.length,  '✅'],
    ['Completed',      myCompleted.length, '🏆'],
    ['Avg Rating',     '4.9 ★',            '⭐'],
  ];

  return (
    <div className="section">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <div>
          <h2 style={{ fontSize: 24, color: 'var(--navy)' }}>Provider Dashboard</h2>
          <p style={{ color: 'var(--gray-500)', marginTop: 4 }}>Find jobs and manage your work</p>
        </div>
        <button className="btn-primary" onClick={onPost}>
          {myProfile ? '✏️ Edit Profile' : '+ Create Profile'}
        </button>
      </div>

      {/* Stats row */}
      <div className="grid-4" style={{ marginBottom: 28 }}>
        {STATS.map(([label, value, icon]) => (
          <div key={label} style={{
            background: 'var(--navy)', borderRadius: 14, padding: '18px 20px', textAlign: 'center',
          }}>
            <div style={{ fontSize: 24, marginBottom: 6 }}>{icon}</div>
            <div style={{ fontFamily: 'Sora', fontSize: 22, fontWeight: 700, color: 'white' }}>{value}</div>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.5)', marginTop: 2 }}>{label}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="tab-pills" style={{ marginBottom: 24 }}>
        {[['available','Available Jobs'],['myjobs','My Accepted Jobs'],['profile','My Profile']].map(([k, l]) => (
          <button key={k} className={`tab-pill ${tab === k ? 'active' : ''}`} onClick={() => setTab(k)}>{l}</button>
        ))}
      </div>

      {/* ---- Available Jobs ---- */}
      {tab === 'available' && (
        <div>
          {available.length === 0 ? (
            <div className="empty-state">
              <div style={{ fontSize: 40, marginBottom: 8 }}>🎉</div>
              <p>No open requests right now. Check back soon!</p>
            </div>
          ) : available.map(b => (
            <div key={b.id} className="card" style={{ marginBottom: 16, display: 'flex', gap: 16, alignItems: 'center' }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, color: 'var(--navy)', fontSize: 16 }}>{b.service}</div>
                <div style={{ fontSize: 13, color: 'var(--gray-500)', marginTop: 2 }}>
                  📅 {b.date} at {b.time} &nbsp;·&nbsp; 📍 {b.zip}
                </div>
                {b.notes && (
                  <div style={{ fontSize: 13, color: 'var(--gray-600)', marginTop: 4 }}>"{b.notes}"</div>
                )}
              </div>
              <div style={{ textAlign: 'center', marginRight: 8 }}>
                <div style={{ fontWeight: 700, fontSize: 20, color: 'var(--green)' }}>${b.price}</div>
                <div style={{ fontSize: 11, color: 'var(--gray-400)' }}>est. pay</div>
              </div>
              <button className="btn-primary btn-sm" onClick={() => onAccept(b.id)}>
                Accept Job ✓
              </button>
            </div>
          ))}
        </div>
      )}

      {/* ---- My Jobs ---- */}
      {tab === 'myjobs' && (
        <div>
          {myAccepted.length === 0 ? (
            <div className="empty-state">
              <p>Accept jobs from the "Available Jobs" tab to see them here.</p>
            </div>
          ) : myAccepted.map(b => (
            <div key={b.id} className="card" style={{ marginBottom: 16 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <div style={{ fontWeight: 600, color: 'var(--navy)' }}>{b.service}</div>
                  <div style={{ fontSize: 13, color: 'var(--gray-500)', marginTop: 2 }}>
                    {b.date} at {b.time} · 📍 {b.zip}
                  </div>
                  {b.notes && <div style={{ fontSize: 13, color: 'var(--gray-600)', marginTop: 4 }}>"{b.notes}"</div>}
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 8 }}>
                  <StatusBadge status={b.status} />
                  <span style={{ fontWeight: 700, color: 'var(--green)' }}>${b.price}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ---- Profile ---- */}
      {tab === 'profile' && (
        <div className="card">
          {myProfile ? (
            <div>
              <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start' }}>
                <Avatar name={myProfile.name} size={64} />
                <div style={{ flex: 1 }}>
                  <h3 style={{ fontSize: 20, color: 'var(--navy)' }}>{myProfile.name}</h3>
                  <Stars rating={myProfile.rating} />
                  <p style={{ fontSize: 14, color: 'var(--gray-600)', marginTop: 8, lineHeight: 1.6 }}>{myProfile.bio}</p>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginTop: 12 }}>
                    {myProfile.skills.map(s => <span key={s} className="badge badge-green">{s}</span>)}
                  </div>
                  <div style={{ fontSize: 13, color: 'var(--gray-500)', marginTop: 12 }}>
                    📍 {myProfile.zip} {myProfile.rate && `· $${myProfile.rate}/hr`}
                  </div>
                </div>
              </div>
              <div style={{ marginTop: 20, paddingTop: 20, borderTop: '1px solid var(--gray-200)' }}>
                <button className="btn-outline btn-sm" onClick={onPost}>Edit Profile</button>
              </div>
            </div>
          ) : (
            <div className="empty-state" style={{ padding: 40 }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>👤</div>
              <h3 style={{ marginBottom: 8 }}>No profile yet</h3>
              <p style={{ marginBottom: 16, color: 'var(--gray-500)' }}>
                Create your provider profile to start appearing in search results and accepting jobs.
              </p>
              <button className="btn-primary" onClick={onPost}>Create Profile</button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
